SELECT count(*) FROM role_type, cast_info, title, char_name, name, movie_companies, movie_keyword, keyword, aka_name WHERE cast_info.role_id = role_type.id AND cast_info.movie_id = title.id AND cast_info.person_role_id = char_name.id AND cast_info.person_id = name.id AND movie_companies.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND aka_name.person_id = name.id;